/**
 * IBM Plex Sans Arabic (SemiBold), base64-embedded for next/og ImageResponse.
 * Embedded — NOT read via fs/fetch — so the Arabic OG font travels with the
 * server bundle and works identically in dev, build, standalone output, and
 * Docker. This is the deliberate fix for the standalone/Docker asset-survival
 * risk (Change #2B). Regenerate with scripts/gen-arabic-font-data if the font
 * changes. Server-only module (imported by the OG route).
 */
const BASE64 =
  '';

/** The font as a Node Buffer, ready to pass to ImageResponse `fonts`. */
export function arabicFontData(): Buffer {
  return Buffer.from(BASE64, 'base64');
}
